// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, client_id, client_secret, code, redirect_uri } = req.body;
  
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'Invalid grant type' });
  }
  
  if (!client_id || !client_secret || !code) {
    return res.status(400).json({ error: 'Missing required parameters' });
  }
  
  const client = clients.get(client_id);
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'Invalid client credentials' });
  }
  
  const authCode = authCodes.get(code);
  if (!authCode || authCode.expires_at < Date.now() || authCode.used) {
    return res.status(400).json({ error: 'Invalid authorization code' });
  }
  
  if (authCode.client_id !== client_id) {
    return res.status(400).json({ error: 'Authorization code mismatch' });
  }
  
  if (redirect_uri && authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'Redirect URI mismatch' });
  }
  
  // Mark code as used
  authCode.used = true;
  authCodes.delete(code);
  
  // Generate access token
  const accessToken = generateAccessToken(client_id, authCode.user_id, authCode.scope);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    scope: authCode.scope
  });
});

// Protected resource endpoint
app.get('/api/user', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or invalid authorization header' });
  }
  
  const token = authHeader.substring(7);
  const accessToken = verifyAccessToken(token);
  
  if (!accessToken) {
    return res.status(401).json({ error: 'Invalid or expired access token' });
  }
  
  res.json({
    user_id: accessToken.user_id,
    client_id: accessToken.client_id,
    scope: accessToken.scope
  });
});

